  tooltip: {
    trigger: 'item',
    formatter: function(params) {
      const d = params.data;
      return `<b>${d.name}</b><br/>
        ${t('Deals')}: ${d.value}<br/>
        ${t('Value')}: ${formatCurrency(d.amount)}<br/>
        ${t('Avg AI Prob')}: ${d.avgProb}%<br/>
        ${t('Avg Deal')}: ${formatCurrency(d.avgSize)}`;
