      gap: 2,
      label: {
        show: true,
        position: 'inside',
        formatter: function(params) {
          const d = params.data;
          return `{name|${d.name}}\n{value|${d.value} ${t('deals')} | ${formatCurrency(d.amount)}}`;
        },
        rich: {
          name: {
            fontSize: 14,
            fontWeight: 'bold',
            color: '#fff'
          },
          value: {
            fontSize: 11,
            color: 'rgba(255,255,255,0.85)'
